class Solution:
    def countCharacters(self, words: List[str], chars: str) -> int:
        count = 0
        for word in words:
            seen = {}
            for char in word:
                if char not in chars or chars.count(char) < word.count(char):
                    break
                seen[char] = True
            else:
                count += len(word)
        return count
```
